const {
              ctx,
              chartArea: { left, right },
              scales: { y },
            } = chart;

ctx.quadraticCurveTo(
  rectX + rectW,
  rectY,
  rectX + rectW,
  rectY + radius
);

ctx.quadraticCurveTo(
  rectX + rectW,
  rectY + h,
  rectX + rectW - radius,
  rectY + h
);

ctx.quadraticCurveTo(
  rectX,
  rectY + h,
  rectX,
  rectY + h - radius
);
